INSERT INTO `categories` (`id`, `name`, `description`, `image_url`, `created_at`, `updated_at`) VALUES
('19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Thịt Gà Đặc Sản', 'Những thớ thịt gà thả vườn săn chắc, tẩm ướp đậm đà gia vị thảo mộc và chế biến bằng sự đam mê.', 'https://www.themealdb.com/images/category/chicken.png', '2026-03-11 23:44:44', '2026-03-11 23:44:44'),
('27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Thịt Bò Thượng Hạng', 'Tuyển tập các món bò nội mọng nước, từ nướng xém cạnh đến hầm rục tủy xương, đánh thức mọi giác quan.', 'https://www.themealdb.com/images/category/beef.png', '2026-03-11 23:44:43', '2026-03-11 23:44:43'),
('346be777-07ed-426f-9be4-9bdec7356dcc', 'Mì Ý Hảo Hạng', 'Tinh hoa ẩm thực Địa Trung Hải với sợi mì luộc Al Dente dòn dai quyện trong làn nước xốt sánh mịn.', 'https://www.themealdb.com/images/category/pasta.png', '2026-03-11 23:44:44', '2026-03-11 23:44:44'),
('41bb93b7-357e-4edd-b1f6-f0221963968c', 'Thịt Lợn Tinh Tuyển', 'Từng dải ba chỉ tươm mỡ hay sườn non nướng cháy cạnh, mang đến sự no đủ và thỏa mãn tuyệt đối.', 'https://www.themealdb.com/images/category/pork.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('56d9060a-cb24-499d-9431-ae5cb161fea8', 'Hải Sản Đại Dương', 'Trọn vẹn hơi thở biển khơi tươi mát từ tôm, cua, cá, mực được đánh bắt và chế biến ngay trong ngày.', 'https://www.themealdb.com/images/category/seafood.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('70144013-483b-445f-b36f-01a2ed3c9eb8', 'Món Ăn Kèm Thanh Tao', 'Những bản phối rau củ và tinh bột nhẹ nhàng, giúp làm sạch vòm miệng và tôn vinh vương vị món chính.', 'https://www.themealdb.com/images/category/side.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Tráng Miệng Lãng Mạn', 'Bản giao hưởng ngọt ngào của bánh ngọt, kem tươi và trái cây, khép lại bữa tiệc một cách hoàn mỹ.', 'https://www.themealdb.com/images/category/dessert.png', '2026-03-11 23:44:44', '2026-03-11 23:44:44'),
('95d9ce28-aa8d-44a9-b099-5556c238a42e', 'Khai Vị Kích Thích', 'Bước dạo đầu đầy tinh tế với những hương vị chua cay mặn ngọt dôn dốt, khơi mào cho yến tiệc.', 'https://www.themealdb.com/images/category/starter.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('c04ad7dc-8a5c-4696-b670-38abe869bce0', 'Thịt Dê Núi Đậm Vị', 'Đặc sản dê núi săn chắc, tẩm ướp bí truyền khử sạch mùi hôi, mang lại trải nghiệm thăng hoa.', 'https://www.themealdb.com/images/category/goat.png', '2026-03-11 23:44:46', '2026-03-11 23:44:46'),
('c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Ẩm Thực Chay', 'Sự kết hợp phong phú giữa rau củ tươi mướt, nấm rừng và phô mai béo ngậy đầy dinh dưỡng.', 'https://www.themealdb.com/images/category/vegetarian.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('d941e6e2-b286-4b60-b280-a78e591142dd', 'Điểm Tâm Sáng', 'Khởi đầu ngày mới rực rỡ với những món ăn nóng hổi, tiếp thêm nguồn năng lượng dồi dào.', 'https://www.themealdb.com/images/category/breakfast.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Cừu Non Đút Lò', 'Thịt cừu non tơ ngấm đẫm hương thảo mộc, nướng chậm mềm tan không lưu lại chút hậu vị ngái.', 'https://www.themealdb.com/images/category/lamb.png', '2026-03-11 23:44:44', '2026-03-11 23:44:44'),
('e35baa1a-0d7e-422c-8513-01ca34591f2d', 'Thuần Chay Tự Nhiên', 'Nét đẹp nguyên bản của thực vật, không bơ sữa, mang lại sự thanh tịnh và an lành cho cơ thể.', 'https://www.themealdb.com/images/category/vegan.png', '2026-03-11 23:44:45', '2026-03-11 23:44:45'),
('eda062c9-466f-4f68-ab6d-675368609649', 'Biến Tấu Độc Bản', 'Những tuyệt tác ẩm thực phá cách, kết hợp nguyên liệu độc đáo không theo bất kỳ khuôn mẫu nào.', 'https://www.themealdb.com/images/category/miscellaneous.png', '2026-03-11 23:44:44', '2026-03-11 23:44:44');
INSERT INTO `menu_items` (`id`, `category_id`, `name`, `description`, `price`, `image_url`, `area`, `is_available`, `is_featured`, `created_at`, `updated_at`) VALUES
('00258eda-d3f5-4dec-9293-86c55504bb6e', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Súp Khoai Tây Hầm Thịt Cừu Chtitha Batata Kiểu Algeria Đậm Đặc Bỏng Rát Cay Xé Lưỡi Đê Mê Tê Ngây', 'Xốt tỏi ớt đập nhồi lỏng nhũn đun lụt nổ lép bép thả cừu khoai luộc bở bục vỡ nước hầm cô đặc váng tươm mỡ.', '75000.00', 'https://www.themealdb.com/images/media/meals/q8pu1k1764114334.jpg/preview', 'Algerian', 1, 0, '2026-03-12 00:04:05', '2026-03-12 00:04:05'),
('00b393cf-a164-439a-bb11-a87187f96836', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Mực Chiên Xù Rang Muối Tiêu Cay Nồng Vỡ Vụn Hạt Béo Bùi Cắn Ngập Răng Xịt Nước Lỏng Le Lỏng Lét Mặn', 'Mực tẩm lựu văng lỏng chiên ngập nổ rộp dòn lõi xốp muối tiêu xào khét xém nứt lỏng lụt lửa.', '120000.00', 'https://www.themealdb.com/images/media/meals/yxiilf1763759428.jpg/preview', 'Vietnamese', 1, 0, '2026-03-12 00:04:11', '2026-03-12 00:04:11'),
('0129a81c-03ea-473e-8896-a1a043b183a6', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Mì Chivito Bò Nướng Kẹp Trứng Xúc Xích Phô Mai Ngập Cốt Chảy', 'Ổ bánh giòn rạn cắn vỡ bọc tảng bò nướng tươm mỡ, trứng đào lỏng nhũn dăm bông xông khói phô mai kéo sợi dính mướt ngon lành.', '200000.00', 'https://www.themealdb.com/images/media/meals/n7qnkb1630444129.jpg/preview', 'Uruguayan', 1, 0, '2026-03-12 00:04:00', '2026-03-12 00:04:00'),
('015f10df-9c84-4c7e-a6d8-1c1f7646e176', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Áp Chảo Hầm Vang Đỏ Coq Au Vin Kiểu Pháp Đậm Đặc Nước Cốt Chua Thanh Chát Đắng Rũ Lưỡi Bươm', 'Thịt ba rọi áp xém khét tươm mỡ xào hành tỏi lụn bại tọng đùi gà lặn ngụp vang đỏ đun bục vỡ ùng ục nấm bở váng lỏng.', '160000.00', 'https://www.themealdb.com/images/media/meals/qstyvs1505931190.jpg/preview', 'French', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('01790205-1ace-4fce-97f8-c9a9f0f0587b', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Mút Xốp Pouding Chomeur Đút Lò Lót Si-rô', 'Cốt bánh bơ nở phồng rộp nứt xốp mịn lặn ngụp dưới dòng si-rô cây phong nóng bỏng đun sôi trào lấp lánh như chiếc gương nước.', '70000.00', 'https://www.themealdb.com/images/media/meals/yqqqwu1511816912.jpg/preview', 'Canadian', 1, 0, '2026-03-12 00:04:38', '2026-03-12 00:04:38'),
('021f74b6-00fe-4f60-8c09-ea4cfaa340c2', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Hủ Tiếu Xào Tôm Áp Chảo Chow Fun Bỏng Lửa Óng Láng Bóng Rẫy Kích Vị Tê Ngây Cực Đỉnh Chua Chát Lừng Danh', 'Phở ngâm bở vỡ lỏng lủng đun lụt ùng sục vớt lỏng lủng xào tôm lựu văng lụn lỏng lụt lắt tươm láng.', '115000.00', 'https://www.themealdb.com/images/media/meals/1529445434.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:15', '2026-03-12 00:04:15'),
('035e0875-4b66-46a0-8fd6-9f773b2100b2', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Om Sốt Vang Đỏ Basquaise Kiểu Pháp', 'Đùi gà nướng xém da hầm nhừ trong xốt cà chua vang đỏ sóng sánh, vị chua chua ngòn ngọt mơn man lưu luyến đầu lưỡi.', '155000.00', 'https://www.themealdb.com/images/media/meals/wruvqv1511880994.jpg/preview', 'French', 1, 0, '2026-03-12 00:03:56', '2026-03-12 00:03:56'),
('03c5488f-14e3-47cd-a86e-1d8649cec13b', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Quẩy Xoắn Churros Phủ Sốt Socola Caramel Muối Mặn Béo Ngậy Chấm Kéo Sợi', 'Bột chiên ngập dầu vỏ nứt rộp phồng dòn rụm lõi xốp dẻo chấm quệt đẫm dòng xốt bơ đường đun chảy sóng sánh lấp lánh.', '135000.00', 'https://www.themealdb.com/images/media/meals/erzs951763296201.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:02', '2026-03-12 00:04:02'),
('04821150-2916-4614-8a34-6745d2cf249b', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Salad Khoai Tây Cà Rốt Trộn Mayonnaise Dưa Chuột Muối', 'Sự kết hợp cổ điển giải ngấy với khoai tây luộc bở thái lựu, dưa leo chua giòn và xốt Mayonnaise kem đặc béo bùi xóc đều.', '60000.00', 'https://www.themealdb.com/images/media/meals/ebvuir1699013665.jpg/preview', 'Russian', 1, 0, '2026-03-12 00:04:38', '2026-03-12 00:04:38'),
('04f9adcc-14d9-4c3a-9518-20fe742b827f', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Thố Xúc Xích Hầm Nghêu Biển Đậu Trắng Nước Cốt Mặn Chát Thơm Dậy Mùi Lấp Liếm Răng Nóng Bỏng', 'Xúc xích áp chảo tươm mỡ láng đỏ xào lướt hành tỏi lụn bại ấp ủ nghêu há bục đậu luộc nhũn lỏng đun bùng nhùng.', '195000.00', 'https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('051c21f9-e5cf-4ce9-b6bc-317788aece17', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Parkin Gừng Yến Mạch Mật Đường', 'Chiếc bánh nướng đậm đà hơi thở mùa đông nước Anh, xốp ẩm bùi béo kết hợp vị gừng ấm áp và lớp mật mía kẹo dính ngọt ngào.', '250000.00', 'https://www.themealdb.com/images/media/meals/qxuqtt1511724269.jpg/preview', 'British', 0, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('0524683e-141c-4772-bd52-820ff27ae3fa', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Thịt Viên Chiên Giòn Bitterballen', 'Khối thịt viên vàng ươm vỏ giòn tan, nhân bên trong là xốt kem bơ hầm thịt bò sền sệt béo ngậy tan chảy khó cưỡng.', '85000.00', 'https://www.themealdb.com/images/media/meals/lhqev81565090111.jpg/preview', 'Dutch', 1, 0, '2026-03-12 00:03:47', '2026-03-12 00:03:47'),
('06047258-2974-4946-a304-bf6453085f1d', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Crêpe Nalesniki Phô Mai Tươi Cuộn Mứt Dâu', 'Lớp bánh mỏng tang vàng ươm cuộn ấp phô mai sữa đông béo ngậy và mứt dâu đỏ au chua thanh, rưới si-rô lóng lánh đậm vị tuổi thơ.', '180000.00', 'https://www.themealdb.com/images/media/meals/58bkyo1593350017.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:04:34', '2026-03-12 00:04:34'),
('068577e5-8a48-429e-8398-2d2577374e59', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Nấu Sốt Cà Chua Marengo Cõng Nấm Rừng Nhừ Tử', 'Xốt cà chua sánh mịn ôm trọn đùi gà áp chảo hầm nhừ vắt cạn ngọt tủy, quyện nấm rừng mềm mọng lún nhẹ nơi răng.', '185000.00', 'https://www.themealdb.com/images/media/meals/qpxvuq1511798906.jpg/preview', 'French', 1, 0, '2026-03-12 00:03:58', '2026-03-12 00:03:58'),
('0723d9e6-92b3-4065-a590-71a328c65a76', 'eda062c9-466f-4f68-ab6d-675368609649', 'Pizza Margherita Lò Gạch Nướng Xém Viền', 'Chiếc pizza kinh điển Napoli vỏ mỏng nướng củi giòn rụm, phủ xốt cà chua chua thanh và phô mai Mozzarella tươi kéo sợi dai dẻo lóng lánh.', '75000.00', 'https://www.themealdb.com/images/media/meals/x0lk931587671540.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:33', '2026-03-12 00:04:33'),
('0733790b-220c-416a-83b5-65d3b8d13203', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Hủ Tiếu Xào Bò Pad See Ew', 'Bản giao hưởng đường phố Thái Lan với sợi hủ tiếu bản to xào xém viền trong xốt tương đen óng ả, ngấm đẫm vị bò tươi mọng nước.', '60000.00', 'https://www.themealdb.com/images/media/meals/uuuspp1468263334.jpg/preview', 'Thai', 1, 0, '2026-03-12 00:04:28', '2026-03-12 00:04:28'),
('07375e53-2ac4-42b8-943d-c30c1c32600d', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Salad Dưa Leo Xào Mè Rang Ngũ Vị Hương Chua Thanh Dôn Dốt Bóng Lộn Dầu Mỡ Nhai Rộp Rộp Đứt Phanh Dòn Sần Sật', 'Dưa lỏng lủng ướp ráo lỏng nhào tã mè láng lỏng lựu văng bắn đun bục lỏng lụt lỏng lợn.', '80000.00', 'https://www.themealdb.com/images/media/meals/93iok31766436070.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:14', '2026-03-12 00:04:14'),
('083dadf8-f251-4cc4-a2bd-b8ffa3a174c0', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Mì Burger Big Mac Trứ Danh', 'Chiếc burger 3 tầng khổng lồ với bò nướng than hoa kẹp phô mai chảy béo ngậy, bao phủ bởi xốt kem chua ngọt đặc trưng.', '105000.00', 'https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg/preview', 'American', 1, 0, '2026-03-12 00:03:47', '2026-03-12 00:03:47'),
('08d946e9-9989-4472-9ce7-bef24ca5bd16', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Bánh Tráng Cuộn Mì Cá Hồi Sốt Chua Cay Dính Mướt Quệt Môi Béo Ngậy Cắn Rập Răng Tuyệt Đỉnh Khó Phai Nhức', 'Mì chần lỏng lủng lặn ngụp nước bốc vớt ráo xốt tương chanh chua lỏng lấp cuộn cá hồi xém rạn nứt.', '85000.00', 'https://www.themealdb.com/images/media/meals/prrirc1763781360.jpg/preview', 'Vietnamese', 1, 0, '2026-03-12 00:04:11', '2026-03-12 00:04:11'),
('0933db6f-e638-486f-b70f-f18c076c1cd8', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Khoai Tây Đút Lò Boulangère Kiểu Pháp', 'Khoai tây xắt lát mỏng đút lò cùng bơ lạt, bề mặt xém vàng ruộm trong khi cốt bên trong thấm đẫm nước dùng bở tơi mềm mịn.', '240000.00', 'https://www.themealdb.com/images/media/meals/qywups1511796761.jpg/preview', 'French', 1, 0, '2026-03-12 00:03:48', '2026-03-12 00:03:48'),
('0a3dae1e-7412-45d2-9a82-fbc30cf8d2c0', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Om Nấm Bơ Nồi Đất Vị Thanh Ngọt', 'Thớ thịt gà hầm mềm rục hòa cùng nấm mọng nước trong làn nước xốt bơ tỏi sánh nhẹ, vắt cạn độ ngọt của nguyên liệu tự nhiên.', '130000.00', 'https://www.themealdb.com/images/media/meals/uuuspp1511297945.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:55', '2026-03-12 00:03:55'),
('0a60c657-0465-4fae-b05c-21d3c900f9cd', 'e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Sườn Cừu Nướng Xốt Ớt Gừng Cay Nồng Phết Đẫm Mướt Mát', 'Dẻ sườn cừu non tơ quết đẫm hỗn hợp xốt tỏi gừng chanh đút lò nướng xém, thịt hồng đào tươm béo ngậy mềm rũ trên đầu lưỡi.', '85000.00', 'https://www.themealdb.com/images/media/meals/8xuvhj1763794991.jpg/preview', 'Turkish', 0, 0, '2026-03-12 00:03:59', '2026-03-12 00:03:59'),
('0abaff13-d082-498c-8e87-6e4d16fa046a', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Hầm Cay Nhừ Chilli Mềm Tan', 'Thớ thịt bò ninh nhừ khóa chặt vị ngọt tủy, đắm chìm trong nước xốt ớt đỏ cay xé lưỡi đậm đà phong vị Nam Mỹ.', '230000.00', 'https://www.themealdb.com/images/media/meals/uuqvwu1504629254.jpg/preview', 'Mexican', 1, 0, '2026-03-12 00:03:50', '2026-03-12 00:03:50'),
('0bf98755-c193-4ffc-bde4-b9f3c2aaba28', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Pie Thịt Băm Pate Chinois Phủ Khoai Tây Xay', 'Món nướng nhiều lớp với đế thịt băm xào hành tỏi đậm đà, hạt ngô ngọt lịm phủ kín bởi lớp khoai tây nghiền bơ sữa xém mặt béo ngậy.', '105000.00', 'https://www.themealdb.com/images/media/meals/yyrrxr1511816289.jpg/preview', 'Canadian', 1, 0, '2026-03-12 00:04:31', '2026-03-12 00:04:31'),
('0c1febab-9f74-4ea8-81ee-b09396f51994', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Súp Bò Hầm Cùng Dumpling Dẻo Thơm', 'Nước súp bò hầm xương đậm đà thanh ngọt, quyện cùng thịt bò xém cạnh mọng nước và viên bột dumpling dẻo mềm.', '100000.00', 'https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:44', '2026-03-12 00:03:44'),
('0c3fabbf-40ce-4d31-a15a-44a25f29cb40', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pancake Chuối Bồng Bềnh', 'Những chiếc bánh xốp mềm, nóng hổi tỏa hương chuối chín tự nhiên và vanilla êm dịu, ăn kèm bơ lạt tan chảy và si-rô phong.', '95000.00', 'https://www.themealdb.com/images/media/meals/sywswr1511383814.jpg/preview', 'American', 1, 0, '2026-03-12 00:03:38', '2026-03-12 00:03:38'),
('0ee0e3fb-dddf-4e92-b496-70530a9328d7', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Taco Cá Chiên Lớp Gia Vị Cajun Tê Tái', 'Phi lê cá tẩm bột chiên bùng nổ nước mọng, áo bên ngoài lớp gia vị Cajun xông khói cay nồng, cuộn trong bánh Tortilla mềm mại.', '55000.00', 'https://www.themealdb.com/images/media/meals/uvuyxu1503067369.jpg/preview', 'Mexican', 1, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('0f056245-292f-487d-b799-f3fa885635bf', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cơm Hải Sản Xào Vang Óng Ả Thảo Mộc Thơm Phức Rục Xương Bở Tơi Nhũn Lụi Rũ Rượi Ngập Cốt Khét Nước Sánh', 'Gạo tã lỏng lủng đun vang sủi ùng tọng hải lựu văng lỏng lủng lạch nát váng đun bục bùng.', '105000.00', 'https://www.themealdb.com/images/media/meals/5r5rvx1763287943.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:12', '2026-03-12 00:04:12'),
('1022e57a-e5f5-4900-b573-d15014b879df', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Salad Quinoa Gà Lưới Kiểu Hy Lạp Xốt Tỏi Bơ Trộn Đều', 'Hạt diêm mạch bung nở tơi xốp hòa ca cùng gà phi lê xốc bơ tỏi, điểm xuyết rau xanh dưa leo giòn mọng thanh mát cơ thể.', '100000.00', 'https://www.themealdb.com/images/media/meals/k29viq1585565980.jpg/preview', 'Greek', 1, 0, '2026-03-12 00:03:58', '2026-03-12 00:03:58'),
('110149b2-7800-42e4-84b4-26d92a01dc1c', '346be777-07ed-426f-9be4-9bdec7356dcc', 'Mì Ý Puttanesca Cà Chua Đen Ô Liu Tỏi Ớt', 'Sợi mì Ý vàng óng luộc chuẩn Al Dente hòa mình trong xốt cà chua cô đặc, cá mòi mặn mòi điểm xuyết nụ bạch hoa chua dịu nức mũi.', '60000.00', 'https://www.themealdb.com/images/media/meals/vvtvtr1511180578.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:32', '2026-03-12 00:04:32'),
('130338bf-f964-4992-b98e-5bc9a78e70ef', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Mì Ý Xốt Bò Băm Cà Chua Bolognese Ngấm Đượm Tuyệt Mỹ Đục Ngầu Nước Hầm Cô Đặc Nhừ Tử Béo Ngậy Tan Chảy', 'Hành xào lụn tươm láng đun lụt gạo lỏng lủng sủi ùng ầm váng tọng bò lựu văng lỏng lủng.', '140000.00', 'https://www.themealdb.com/images/media/meals/sutysw1468247559.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:18', '2026-03-12 00:04:18'),
('1421a4a2-cdf0-4a46-83cf-abe519157936', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Cupcake Socola Kunafa Phủ Kem Hạt Dẻ Cười', 'Khúc biến tấu phương Đông với lõi bánh ngọt lịm socola, trùm chiếc mền sợi mì Kunafa nướng giòn rụm bùi béo tan ngay trong miệng.', '125000.00', 'https://www.themealdb.com/images/media/meals/yh3sg71763741307.jpg/preview', 'Saudi Arabian', 0, 0, '2026-03-12 00:04:32', '2026-03-12 00:04:32'),
('14a5707d-3178-4235-9391-97d57a59b335', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Thịt Băm Cuộn Đút Lò Xốt Đậu Nành Ngọt Nước Sốt Wasabi Cà Rốt Ngọt Lịm Khó Cưỡng Nứt Nẻ Tỏa Hương Béo Bùi', 'Thịt lỏng lủng đập nhồi ấp đun lụt ùng sục đút nướng xém rạn vỡ lõi nhũn lụi rũ lỏng láng.', '115000.00', 'https://www.themealdb.com/images/media/meals/o2wb6p1581005243.jpg/preview', 'American', 0, 0, '2026-03-12 00:04:17', '2026-03-12 00:04:17'),
('14d9d8c1-8e0b-4624-b163-494ccdc7a5ef', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Súp Đậu Hà Lan Tách Hạt Hầm Thịt Heo Hà Lan Cô Đặc Nhừ Tử Béo Ngậy Tan Chảy Ngập Lối Mặn Mòi Rát Lưỡi Đê Mê', 'Đậu lỏng lủng luộc bở vỡ vớt lỏng tươm láng xốt tương lỏng lụt lắt tươm láng thịt xào lộn.', '220000.00', 'https://www.themealdb.com/images/media/meals/9ptx0a1565090843.jpg/preview', 'Dutch', 1, 0, '2026-03-12 00:04:17', '2026-03-12 00:04:17'),
('157053d5-c4b6-44d3-b3ff-cb0a684fa997', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Bông Lan Cà Rốt Hạt Óc Chó', 'Cốt bánh xốp mịn lấm tấm vụn cà rốt đỏ au tươm ẩm, điểm hạt óc chó bùi béo đan xen lớp kem phủ phô mai cream cheese thanh chua.', '180000.00', 'https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('1671069d-472f-4eec-a01e-52deab2ad846', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Đậu Trắng Hầm Lườn Gà Cùng Xúc Xích Khói Chorizo Mãn Nhãn Kéo Sợi Bóng Láng Ngập Ngụa Cắn Rập Răng Tuyệt Đỉnh', 'Khoai luộc bở nhũn xào gà áp tươm láng đổ trứng đun rát váng xém bục nứt rỗng bỏ lỏng.', '235000.00', 'https://www.themealdb.com/images/media/meals/bpkxtw1763332446.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:18', '2026-03-12 00:04:18'),
('17a013f4-21c5-43ae-8f0c-9b60979ee921', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Trứng Đút Lò Xốt Cà Chua Cà Tím Pisto', 'Phiên bản Ratatouille xứ Tây Ban Nha với rau củ xào nhừ mọng nước, ôm trọn những quả trứng đút lò với phần lòng đỏ đào tan chảy êm ái.', '230000.00', 'https://www.themealdb.com/images/media/meals/0nswfe1763279040.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:33', '2026-03-12 00:04:33'),
('19ce10d9-e711-491e-bc16-fe4fa0633195', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cá Chẽm Đút Lò Xốt Morocco', 'Thớ cá chẽm trắng ngần được tẩm ướp xốt thảo mộc Morocco đút lò xém mặt, mang đến hương vị cay nồng tinh tế đánh thức vị giác.', '185000.00', 'https://www.themealdb.com/images/media/meals/4o4wh11761848573.jpg/preview', 'Australian', 1, 1, '2026-03-12 00:03:38', '2026-03-12 00:03:38'),
('1a4f254b-676e-4088-885d-1bb941211852', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Trứng Cà Chua Xào Tơi Kiểu Hoa Nước Cốt Ngọt Lịm Đưa Cơm', 'Trứng tráng tơi xốp hòa quyện cà chua mọng nước xào nhừ, lớp nước cốt thanh ngọt tự nhiên lan tỏa trọn vẹn vị mộc mạc đưa cơm.', '100000.00', 'https://www.themealdb.com/images/media/meals/rwvw8q1765660071.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:00', '2026-03-12 00:04:00'),
('1c42e8be-5134-45e1-b9ac-65ec0a3c6425', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Hầm Rau Củ Lapskaus Na Uy', 'Thịt bò ninh chậm rã mềm tủy, quyện đặc xốt sền sệt thanh ngọt từ khoai tây và hành tây mọng nước giải ngấy hoàn hảo.', '190000.00', 'https://www.themealdb.com/images/media/meals/6vi2cv1763075785.jpg/preview', 'Norwegian', 1, 0, '2026-03-12 00:03:52', '2026-03-12 00:03:52'),
('1d4970f9-797f-4e47-b0f6-c5f3dac016fc', 'd941e6e2-b286-4b60-b280-a78e591142dd', 'Trứng Chần Sốt Bơ Hollandaise Cá Hồi Xông Khói Béo Ngậy Tan Chảy Ngập Lối Rũ Lưỡi Nát Bươm Mặn Chát Thơm', 'Lòng đỏ đánh tã lỏng đun lụt ùng xốt bơ chanh chua dôn lỏng lấp trứng chần lỏng lủng đun bục.', '180000.00', 'https://www.themealdb.com/images/media/meals/1550440197.jpg/preview', 'American', 0, 0, '2026-03-12 00:04:10', '2026-03-12 00:04:10'),
('1d626ec5-40df-477e-b9d5-7d90c8ece1a6', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Thịt Heo Đút Lò Hầm Rượu Táo Cider Chua Chát Mặn Mòi Mềm Rục Tủy Xương Rã Tơi Xốp Phồng Rộp Nứt', 'Sườn áp chảo tươm bơ láng xém viền đút thố lụt vang táo đun ùng ục váng khoai cà rốt bở tơi nhũn lụi lỏng rũ.', '170000.00', 'https://www.themealdb.com/images/media/meals/7vpsfp1608588991.jpg/preview', 'Irish', 0, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('1e13a0ca-8dfe-4458-8fae-7432d0365981', 'e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Cà Chua Nhồi Thịt Cừu Nướng Xém Cạnh Mọng Nước Bỏng Rẫy Lan Tỏa Thơm Nức Ngất Ngây Rục Xương Bở Tơi Nhũn Lụi Rũ Rượi Ngập Cốt Khét Nước Sánh', 'Cà tã lỏng lủng đun lụt sủi ùng tọng lựu văng lỏng lủng lạch nát váng đun bục bùng.', '105000.00', 'https://www.themealdb.com/images/media/meals/u55lbp1585564013.jpg/preview', 'Greek', 1, 0, '2026-03-12 00:04:26', '2026-03-12 00:04:26'),
('1e7c36d6-c864-44c4-89e2-bbbd652f257e', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Cơm Bò Nướng Mandi Ả Rập', 'Cơm Basmati hạt dài ướp nghệ vàng ươm, phục vụ cùng thịt bò nướng chậm thơm lừng hương bơ ghee, tỏi và thảo quả.', '235000.00', 'https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg/preview', 'Indian', 1, 0, '2026-03-12 00:03:44', '2026-03-12 00:03:44'),
('1f18a50d-16ce-47ad-a50f-cac56c2d3e71', 'eda062c9-466f-4f68-ab6d-675368609649', 'Bánh Mì Dẹt Syria Nướng Chảo', 'Ổ bánh mì thủ công nướng xém trên chảo gang, ruột bánh xốp phồng dai dẻo cực kỳ bắt vị khi chấm kèm các loại xốt Trung Đông.', '75000.00', 'https://www.themealdb.com/images/media/meals/54xzk31760524666.jpg/preview', 'Syrian', 1, 0, '2026-03-12 00:04:27', '2026-03-12 00:04:27'),
