('36b8f28d-20bc-4b2b-9487-2cfaccc76ab3', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Thịt Hầm Bắp Cải Truyền Thống Ba Lan', 'Hương vị truyền thống Ba Lan với bắp cải hầm nước xương ngọt thanh, điểm tô nấm rừng ngâm nở dai giòn mang dư vị nồng nàn.', '180000.00', 'https://www.themealdb.com/images/media/meals/fl4brj1764361323.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:03:47', '2026-03-12 00:03:47'),
('3763501b-07f5-481d-8dd2-548a2c2aaf92', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Bánh Tacos Gà Phủ Phô Mai Đút Lò Xém Mặt Phô Mai Béo Bùi Khét Ngọt Rộp Vỏ Giòn Rụm Lóng Lánh Chảy Đáy', 'Lườn gà tọng nồi lặn ngụp xốt rưới lỏng lấp gia vị lộn lạch đun bục bùng rũ liệt đứt nhão.', '105000.00', 'https://www.themealdb.com/images/media/meals/ypxvwv1505333929.jpg/preview', 'Mexican', 1, 0, '2026-03-12 00:04:09', '2026-03-12 00:04:09'),
('39f6f690-13fd-4f46-81c7-35790d7014b8', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Súp Củ Dền Đỏ Borscht Kiểu Nga', 'Bát súp màu ngọc thạch lựu rực rỡ, hầm nhừ củ dền ngọt lịm cùng nước dùng đậm đà, mang đến sự ấm áp từ xứ sở Bạch Dương.', '120000.00', 'https://www.themealdb.com/images/media/meals/zadvgb1699012544.jpg/preview', 'Ukrainian', 1, 0, '2026-03-12 00:03:47', '2026-03-12 00:03:47'),
('3ad407b0-de73-4277-b92e-47383587d529', '95d9ce28-aa8d-44a9-b099-5556c238a42e', 'Súp Kem Cà Chua Cay Nồng Sánh Sệt Cô Đặc Nhừ Tử Khét Nước Nhũn Lụi Rũ Rượi Xay Nhuyễn Béo Ngậy Tan', 'Rau củ xào lụn bại tươm dầu láng đun lụt nước ùng ục váng cà chua bục vỡ lỏng lủng củng xay nhũn lột nát láng mượt.', '130000.00', 'https://www.themealdb.com/images/media/meals/stpuws1511191310.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('3c4f2440-99ac-431a-882c-6d31b3b04cac', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Bánh Xèo Cuộn Gia Vị Ớt Cay Ấn Độ Cuốn Hút Tột Độ Cay Xé Bỏng Rát Cô Đặc Nhừ Tử Khét Nước Nhũn Lụi Rũ Rượi', 'Bột đánh tã lỏng đun cà ùng xốt tỏi đập lỏng lấp trứng lỏng lủng đun bục.', '210000.00', 'https://www.themealdb.com/images/media/meals/7b862e1763194846.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:21', '2026-03-12 00:04:21'),
('3cfb39e9-2f15-45d4-afb6-dbaf20690b37', '346be777-07ed-426f-9be4-9bdec7356dcc', 'Mì Spaghetti Đút Lò Bò Băm Phô Mai Chảy', 'Thố mì ống đút lò nóng hổi quyện trong xốt bò băm cà chua đậm đặc, phủ lên trên là lớp phô mai nướng váng vàng ươm béo ngậy.', '250000.00', 'https://www.themealdb.com/images/media/meals/5fu4ew1760524857.jpg/preview', 'Syrian', 1, 0, '2026-03-12 00:04:28', '2026-03-12 00:04:28'),
('3d8473b4-2ce5-495b-990e-da23d2861a84', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Bông Lan Cờ Vua Battenberg', 'Khúc biến tấu nghệ thuật với hai sắc màu bông lan đan xen, kết dính bằng mứt mơ chua thanh và bọc ngoài bởi lớp hạnh nhân marzipan dẻo mịn.', '110000.00', 'https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:40', '2026-03-12 00:03:40'),
