('61164834-0f43-4aa2-bb3c-427cd594d72b', 'eda062c9-466f-4f68-ab6d-675368609649', 'Tempura Bông Cải Tím Giòn Rụm Phủ Bột Mỏng Tang', 'Hoa lơ áo lớp bột lạnh mỏng manh chiên ngập dầu nổ lép bép vỡ vụn giòn tan vỏ nhưng vẫn giữ vẹn nguyên độ ngọt thanh mọng nước cốt bên trong.', '110000.00', 'https://www.themealdb.com/images/media/meals/xnv4wf1763756529.jpg/preview', 'Vietnamese', 1, 0, '2026-03-12 00:04:42', '2026-03-12 00:04:42'),
('63cda0a2-4bf4-4a95-bbc4-496ee24714df', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Tart Hạnh Nhân Bakewell', 'Chiếc bánh ngọt ngào phong cách Anh Quốc với đế bơ giòn tan, nhân mứt mâm xôi chua dịu và lớp xốp hạnh nhân nướng vàng ruộm.', '215000.00', 'https://www.themealdb.com/images/media/meals/wyrqqq1468233628.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:38', '2026-03-12 00:03:38'),
('640ca6ab-f211-430f-bf1c-c31fff953065', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Sốt Cà Tím Nướng Baba Ghanoush', 'Món khai vị trứ danh Địa Trung Hải với cà tím nướng than hoa đánh nhuyễn, hòa quyện cùng bơ mè Tahini béo ngậy, tỏi thơm và dầu ô-liu nguyên chất.', '110000.00', 'https://www.themealdb.com/images/media/meals/dlmh401760524897.jpg/preview', 'Syrian', 1, 0, '2026-03-12 00:03:37', '2026-03-12 00:03:37'),
('650ac59e-750a-4c60-a1d5-fb006ce893af', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Muối Corned Beef Hầm Bắp Cải Tươi Rục Xương Bở Tơi Nhũn Lụi Rũ Rượi Ngập Cốt Thơm Nồng Mọng', 'Tảng bò đỏ đun lụt ngập nước ủ gia vị sùng sục váng hạ lửa liu riu lụn bại rã rượi tọng bắp cải lỏng nhũn lột đứt.', '220000.00', 'https://www.themealdb.com/images/media/meals/xb97a81583266727.jpg/preview', 'Irish', 0, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('651e332e-12ab-4a21-a3d8-0c6c60a81771', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Xốp Việt Quất Friands Lõi Chanh Tươi', 'Cắn vào lớp vỏ bánh bơ nướng hạnh nhân xốp nhẹ, cảm nhận trọn vẹn sự tươi mát của việt quất mọng nước và mứt chanh vàng.', '145000.00', 'https://www.themealdb.com/images/media/meals/e756bf1761848342.jpg/preview', 'Australian', 1, 0, '2026-03-12 00:03:48', '2026-03-12 00:03:48'),
('6643823e-0ba0-4268-8724-f43516f27245', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Sủi Cảo Khoai Tây Phủ Hạt Poppy Chấm Bơ Sữa Đường Ngọt Ngất Ngây Dẻo Quánh Lưỡi Lan Tỏa Nức Nở Nóng Bỏng Rát Lưỡi Đê Mê Trứ Danh Lấp Liếm Răng Khó Phai Nhức Nách', 'Sủi lỏng lủng ấp chảo lỏng xốt đun lụt sùng ầm váng tỏi lựu lỏng lụt lắt tươm láng xào lạch.', '200000.00', 'https://www.themealdb.com/images/media/meals/d6o4nu1763362422.jpg/preview', 'Slovakian', 1, 0, '2026-03-12 00:04:27', '2026-03-12 00:04:27'),
('66847cb3-a1e7-4252-981c-62bcfc16ad4f', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Bánh Xếp Ngàn Lớp Nhồi Bò Băm Burek', 'Vỏ bánh pastry dát mỏng tang nướng xém vỡ rụm tan trong miệng, ấp ủ phần nhân bò băm xào hành tây ướp tiêu đen đậm vị.', '145000.00', 'https://www.themealdb.com/images/media/meals/tkxquw1628771028.jpg/preview', 'Croatian', 1, 0, '2026-03-12 00:03:52', '2026-03-12 00:03:52'),
('66ca1146-8a7a-4929-b4ad-8973ff26bb77', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Bánh Mì Pita Nướng Xếp Shawarma Áp Chảo Rỗng Khí Bồng Bềnh Rút Lõi Mềm Nhũn Chảy Lóng Lánh Nóng Bỏng', 'Bột lỏng lủng đập nhồi ấp đun lụt ùng sục đút nướng xém vỡ lõi nhũn lụi rũ lỏng láng dính.', '230000.00', 'https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg/preview', 'Saudi Arabian', 1, 0, '2026-03-12 00:04:15', '2026-03-12 00:04:15');
INSERT INTO `menu_items` (`id`, `category_id`, `name`, `description`, `price`, `image_url`, `area`, `is_available`, `is_featured`, `created_at`, `updated_at`) VALUES
('66ca3694-a37d-49d4-899d-47e1b1101bdb', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Thố Đậu Hầm Xúc Xích Kiểu Croatia Đậm Vị Rục Xương Bở Tơi Nhũn Lụi Rũ Rượi Ngập Cốt Khét Nước Sánh', 'Rau củ xào lụn bại tươm đun đậu luộc bở váng xúc xích lặn ngụp bục 20 phút lỏng lủng lạch nát.', '100000.00', 'https://www.themealdb.com/images/media/meals/tnwy8m1628770384.jpg/preview', 'Croatian', 1, 0, '2026-03-12 00:04:08', '2026-03-12 00:04:08'),
('6799e349-2103-47c5-af32-8e587a838cc7', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Hầm Vang Đỏ Bourguignon Kiểu Pháp', 'Tinh hoa ẩm thực Pháp với khối bò hầm liu riu nhiều giờ trong rượu vang đỏ hảo hạng, điểm xuyết nấm rừng và mỡ ngỗng béo ngậy.', '50000.00', 'https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg/preview', 'French', 1, 0, '2026-03-12 00:03:42', '2026-03-12 00:03:42'),
('6816f102-e57d-4f2b-90f2-6151c1bce958', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cơm Risotto Nấu Chậm Tôm Cá Hồi Đục Ngầu Nước Hầm Cô Đặc Nhừ Tử Béo Ngậy Tan Chảy Ngập Lối Mặn Mòi Rát', 'Hành xào lụn tươm láng đun lụt lỏng lủng vang sủi ùng váng tọng tôm cá hồi lựu văng lỏng lủng lạch nát đun bùng.', '120000.00', 'https://www.themealdb.com/images/media/meals/xxrxux1503070723.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:11', '2026-03-12 00:04:11'),
('682eca1b-01a5-475d-a1fd-5a7ff6941197', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Thịt Lợn Nướng Than Hoa Áp Chảo Febras Assadas', 'Thịt nạc heo thái mỏng ướp tỏi rượu vang áp chảo lửa lớn cho đến khi cháy xém viền xông khói, đánh thức vị giác mạnh mẽ tột bậc.', '50000.00', 'https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg/preview', 'Portuguese', 1, 0, '2026-03-12 00:04:37', '2026-03-12 00:04:37'),
('68d0fb23-c2a2-41cc-930a-329f5cd06740', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cơm Paella Hải Sản Vang Trắng', 'Chảo cơm dẹt giòn đáy đặc trưng Tây Ban Nha, ngậm no nước hầm tôm ngọt lịm điểm xuyết hương vang trắng thanh tao ôm trọn hải sản tươi sống.', '190000.00', 'https://www.themealdb.com/images/media/meals/9bl20p1763248192.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('691d9e34-f1c5-4f74-8f01-f277c3e0dea2', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Bữa Sáng Bánh Khoai Tây Ái Nhĩ Lan Boxty', 'Sự kết hợp giữa khoai luộc bở tơi và khoai bào giòn sần sật, chiên xém cạnh vàng ươm mang đến bữa sáng vững chãi.', '235000.00', 'https://www.themealdb.com/images/media/meals/naqyel1608588563.jpg/preview', 'Irish', 0, 0, '2026-03-12 00:03:49', '2026-03-12 00:03:49'),
('69c5a74f-31ec-434b-af7f-6c58cf07259a', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Muối Corned Beef Cuộn Bắp Cải Kiểu Jamaica Áp Chảo Khét Lẹt Xém Cạnh Dòn Sần Sật Rũ Lưỡi Nát Bươm', 'Hành ớt xào lụn bại tươm dầu láng tỏi phi nổ tọng bắp cải băm tã bò muối xé phay đảo lộn xộn lỏng đun bùng nhùng.', '160000.00', 'https://www.themealdb.com/images/media/meals/kdz63q1764793442.jpg/preview', 'Jamaican', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('6b3daf62-0406-4330-8ae9-bdf6eddb79f9', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Xếp Nhồi Thịt Bò Empanadas', 'Chiếc bánh gối nướng phồng rộp hoàn mỹ với lớp vỏ xốp dẻo ngậm bơ, ấp ủ phần nhân bò băm đậm đà gia vị thảo mộc Nam Mỹ.', '205000.00', 'https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg/preview', 'Uruguayan', 1, 0, '2026-03-12 00:03:44', '2026-03-12 00:03:44'),
('6ce71ee7-a9c0-4272-8b9c-77e3ad90a1bb', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Ngọt Alfajores Kẹp Kem Socola Nam Mỹ Giòn Xốp Vỡ Vụn Mịn Màng', 'Cặp bánh bơ nướng xốp xộp vỡ vụn tơi bời kẹp lõi xốt kẹo sữa caramel mặn chát lỏng nhũn dẻo quánh tan chảy đê mê.', '230000.00', 'https://www.themealdb.com/images/media/meals/k9o0xr1764373018.jpg/preview', 'Uruguayan', 1, 0, '2026-03-12 00:04:01', '2026-03-12 00:04:01'),
('6d0455fe-e58c-4cec-8927-88deba5a4247', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Salad Khoai Lang Đút Lò Kèm Sốt Dầu Giấm', 'Khoai lang đút lò nướng xém cạnh dẻo ngọt, trộn đều cùng rau mầm xanh mướt và xốt dầu giấm ô-liu thanh mát dịu nhẹ.', '190000.00', 'https://www.themealdb.com/images/media/meals/z458v91763817681.jpg/preview', 'Turkish', 0, 0, '2026-03-12 00:04:27', '2026-03-12 00:04:27'),
('6d051bb0-a9d4-420e-980a-6ac084dfa69f', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Xào Sốt Kem Nấm Stroganoff', 'Thăn bò mềm mại tắm trong lớp xốt kem chua nấm rừng béo ngậy láng mượt, mang đến trải nghiệm tinh tế trên từng gai vị giác.', '240000.00', 'https://www.themealdb.com/images/media/meals/svprys1511176755.jpg/preview', 'Russian', 1, 0, '2026-03-12 00:03:45', '2026-03-12 00:03:45'),
('6d14d155-0b8a-4a6f-8e88-a44d9e8d5666', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Hủ Tiếu Pad Thai Tôm Chua Cay Ngọt', 'Sợi mì gạo dẻo dai xóc đều tôm nõn giòn sần sật, hòa quyện vị chua thanh của me, ngọt dịu của củ cải muối và bùi béo đậu phộng rang.', '115000.00', 'https://www.themealdb.com/images/media/meals/rg9ze01763479093.jpg/preview', 'Thai', 1, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('6d43e8d9-295d-4ec5-bde0-8cc78519e500', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cơm Chảo Gang Xào Tôm Nõn Múp Míp Ám Khói Xúc Xích Chuẩn Vị Tây Ban Nha Chua Chát Mặn Mòi Mềm Rục Tủy Xương Rã Tơi Xốp Phồng Rộp Nứt', 'Tôm xào khét xém nứt lỏng đun lụt ùng sục lặn bục nhồi đập nhồi luộc dập lỏng lủng.', '100000.00', 'https://www.themealdb.com/images/media/meals/sl6vqv1763335988.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:19', '2026-03-12 00:04:19'),
('6e923a83-4180-4899-934f-dcfc6f4c46b0', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Đuôi Hải Ly BeaverTails Phủ Quế', 'Bánh bột chiên tạo hình độc đáo của Canada, vỏ ngoài giòn rụm phủ đầy đường quế thơm lừng, bên trong dẻo dai khó cưỡng.', '150000.00', 'https://www.themealdb.com/images/media/meals/ryppsv1511815505.jpg/preview', 'Canadian', 0, 0, '2026-03-12 00:03:40', '2026-03-12 00:03:40'),
('6f87afcf-5969-4073-b422-38bd2748a0d8', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Thanh Bánh Yến Mạch Flapjack Vị Pudding Giáng Sinh Si-rô Dính Mướt Kẹt Răng Dẻo Quánh Khó Dứt', 'Bơ đun lỏng hòa quyện si-rô mật đặc nhào yến mạch nướng xém rạn nứt vỡ bùi béo nhai giòn rộp rộp dẻo dính.', '210000.00', 'https://www.themealdb.com/images/media/meals/vvusxs1483907034.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:04', '2026-03-12 00:04:04'),
('7044eff5-2a37-468a-bb40-7552995cdf00', 'e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Thịt Cừu Nướng Chậm Nhồi Quế Hồi Thì Là & Nước Ép Cam Chanh Khét Lẹt Nổ Văng Giòn Sần Sật Tươm Mỡ Đỏ Cháy Xém', 'Cừu lỏng nướng khét láng cuộn lấp xốt lỏng lựu văng bắn xóc lộn đứt lỏng lủng.', '95000.00', 'https://www.themealdb.com/images/media/meals/gr4lo51763791826.jpg/preview', 'Turkish', 1, 0, '2026-03-12 00:04:16', '2026-03-12 00:04:16'),
('70abeb5f-cc45-43ca-8bcc-202d8d8e3fa6', 'e35baa1a-0d7e-422c-8513-01ca34591f2d', 'Ớt Padron Nướng Xém Phủ Muối Biển', 'Những quả ớt xanh mướt áp chảo cháy xém vỏ, giữ trọn vị đắng nhẹ tinh tế và giòn ngọt, điểm xuyết tinh thể muối biển mặn mòi.', '80000.00', 'https://www.themealdb.com/images/media/meals/0ljvc51763248075.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('721bd813-445b-41ef-a345-5b28179f0579', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cá Tuyết Muối Xào Quả Ackee Mềm Tan Mọng Nước Chua Thanh Dôn Dốt Bóng Lộn Dầu Mỡ Nhai Rộp Rộp Đứt Phanh', 'Cá ngâm bở vỡ đun lụt lặn ngụp vớt lỏng lủng xào ackee lụn rũ lỏng lụt lắt tươm láng.', '85000.00', 'https://www.themealdb.com/images/media/meals/vytypy1511883765.jpg/preview', 'Jamaican', 0, 0, '2026-03-12 00:04:12', '2026-03-12 00:04:12'),
('722e4bd5-9d89-45be-a9b6-66409931e0d7', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Xào Húng Quế Ớt Tươi Vị Trát Rát Đắng Bỏng Rát Lưỡi Ngạt Khói Lan Tỏa Lấp Liếm Răng Khó Phai Nhức Nách Đỉnh Bậc Tây Ban Nha Chói Lòa', 'Gà lỏng lủng đập nhồi ấp trái mọng xào lỏng đun lụt ùng sục lạch váng.', '150000.00', 'https://www.themealdb.com/images/media/meals/el64dy1763483009.jpg/preview', 'Thai', 1, 0, '2026-03-12 00:04:25', '2026-03-12 00:04:25'),
('7348026a-76df-4b11-a326-4b2f70d99db8', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Súp Đậu Chẻ Hầm Tỏi Tây Bí Ngòi Xốt Húng Quế Mùa Hè Rực Rỡ Đậm Vị Mãn Nhãn Kích Thích Thị Giác Béo Ngậy Cắn Vỡ Vỏ Rụm Lóng Lánh Chảy Đáy Dính Mướt Quệt Môi', 'Súp lỏng lựu văng lặn ngụp xốt đun bục lỏng tọng lỏng lủng lạch đứt đun bục bùng.', '135000.00', 'https://www.themealdb.com/images/media/meals/rqtxvr1511792990.jpg/preview', 'French', 1, 0, '2026-03-12 00:04:27', '2026-03-12 00:04:27'),
('746e2b2c-9401-49b1-8852-61dcccf3dd81', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Súp Đậu Gà Hầm Xúc Xích Chorizo Đậm Đà Nước Cốt Chua Chát Lừng Danh Rũ Lưỡi Nát Bươm', 'Nồi hầm đun xốt cà chua cô đặc vắt ngọt tủy xúc xích xông khói áp chảo tươm váng láng mỡ ấp ủ đậu gà mềm.', '250000.00', 'https://www.themealdb.com/images/media/meals/kggfo91763288633.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:04', '2026-03-12 00:04:04'),
('7521072d-be17-409e-9628-e6270d87f6f8', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Sườn Heo Áp Chảo Cốt Táo Kèm Khoai Bí Mật Xém Cạnh Rạn Nứt Nẻ Lỏng Lợn Cợn Lủng Củng Đun Bục Bùng Nhùng', 'Sườn lỏng lủng áp tươm láng rắc khoai tã đút rát xém rạn nứt lỏng lủng đun bục bùng lụn lỏng.', '140000.00', 'https://www.themealdb.com/images/media/meals/h3ijwo1581013377.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:16', '2026-03-12 00:04:16'),
('77173114-5b0a-4efc-8d3c-73113592ac01', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Dâu Tây Romanoff Tươi Mát Rượu Vang Đỏ Mọng Tê Tái Đê Mê Ngây Ngất Giác Quan Chua Chát Mặn Mòi Mềm Rục Tủy Xương Rã Tơi Xốp Phồng Rộp Nứt', 'Dâu xào khét xém nứt lỏng đun lụt ùng sục lặn bục nhồi đập nhồi luộc dập lỏng lủng.', '115000.00', 'https://www.themealdb.com/images/media/meals/oe8rg51699014028.jpg/preview', 'Russian', 1, 0, '2026-03-12 00:04:26', '2026-03-12 00:04:26'),
