('93b7f8ff-5f71-41f1-bab3-1233883f3a51', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Bánh Cuộn Phô Mai Borek Ngàn Lớp Nướng Giòn', 'Khối phô mai Gouda béo ngậy tan chảy bọc lấp trong màng bánh bột pastry mỏng tang, đút lò nướng phồng giòn vỡ rụm vang khắp khoang miệng.', '50000.00', 'https://www.themealdb.com/images/media/meals/oal8x31764119345.jpg/preview', 'Algerian', 1, 0, '2026-03-12 00:03:55', '2026-03-12 00:03:55'),
('94dce291-dd47-4b41-bcb9-5b543807ef69', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Quy Hạt Điều Ghoriba Hoa Cam', 'Chiếc bánh nướng rạn nứt bề mặt kiêu hãnh giòn vỡ vụn, ngập tràn vị bùi hạt điều xay nhuyễn và hương tinh dầu hoa cam nhẹ nhàng.', '200000.00', 'https://www.themealdb.com/images/media/meals/t3r3ka1560461972.jpg/preview', 'Tunisian', 1, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('94de7ea4-6d52-483c-95ab-7dc6a1a7c0b1', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pie Dâu Tây Đại Hoàng Nướng Xốp Giòn Chua Ngọt Vỡ Đáy Nứt Cạnh Lóng Lánh Dính Mướt Quệt Môi Béo Ngậy Cắn Rập Răng Tuyệt Đỉnh Khó Phai Nhức', 'Bánh lỏng lủng xát ném lựu văng áp tươm láng rắc hành tỏi lụn lỏng lủng đun bục bùng lụn.', '230000.00', 'https://www.themealdb.com/images/media/meals/178z5o1585514569.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:26', '2026-03-12 00:04:26'),
('9589ba0e-35c9-4b07-acbf-c9eba8ac42bc', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Cà Tím Phủ Bột Chiên Giòn Khụm Vỡ Vụn Hạt Béo Bùi Cắn Ngập Răng Xịt Nước Lỏng Le Lỏng Lét Mặn Chát', 'Lát cà mọng ướp muối vắt lỏng lủng củng tẩm áo bột chiên ngập dầu nổ lạt rộp phồng dòn rụm lõi xốp nhũn lụi rũ.', '150000.00', 'https://www.themealdb.com/images/media/meals/c7lzrl1683208757.jpg/preview', 'Filipino', 1, 0, '2026-03-12 00:04:08', '2026-03-12 00:04:08'),
('96df6b82-442d-4adc-a2cf-b3090937c887', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Cà Tím Xào Gia Vị Ấn Baingan Bharta', 'Sự bùng nổ hương vị từ cà tím nướng lửa hồng dầm nhuyễn, xào đậm đà cùng cà chua tươi và bộ gia vị thảo mộc truyền thống Ấn Độ.', '125000.00', 'https://www.themealdb.com/images/media/meals/urtpqw1487341253.jpg/preview', 'Indian', 1, 0, '2026-03-12 00:03:38', '2026-03-12 00:03:38'),
('97241a67-7d64-4169-93c6-203403fe3d7b', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Cơm Gà Mandi Ả Rập Rắc Nghệ Vàng Hươm', 'Cơm hạt dài tơi xốp nhuộm vàng nghệ xào bơ ghee cõng lườn thịt gà xẻ dọc nướng xém khói, rắc tỏi ớt phi cay nồng.', '180000.00', 'https://www.themealdb.com/images/media/meals/er4d081765186828.jpg/preview', 'Indian', 1, 0, '2026-03-12 00:03:58', '2026-03-12 00:03:58'),
('9777a9b4-7023-47e0-a8b8-9c1b00018f21', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Xôi Lớp Trứng Sữa Nước Cốt Dừa Seri Muka Đậm Chất Malaysia Béo Ngậy Đỉnh Bậc Lóng Lánh Chảy Đáy Dính Mướt', 'Nếp luộc dập lỏng lủng lặn ngụp ấp cốt dừa lỏng rũ trứng đánh tã đút rạn bục khò khét láng lỏng rũ.', '245000.00', 'https://www.themealdb.com/images/media/meals/6ut2og1619790195.jpg/preview', 'Malaysian', 1, 0, '2026-03-12 00:04:13', '2026-03-12 00:04:13'),
('980e2e7d-15df-4913-8a1d-fe80db9589af', 'd941e6e2-b286-4b60-b280-a78e591142dd', 'Cơm Cá Haddock Xông Khói Trộn Trứng Cà Ri Ấn Độ Trứ Danh Óng Láng Bóng Rẫy Kích Vị Tê Ngây Cực Đỉnh Chua Chát', 'Cá ngâm bở vỡ lỏng lủng đun lụt ùng sục vớt lỏng lủng xào trứng lựu văng lụn lỏng lụt.', '105000.00', 'https://www.themealdb.com/images/media/meals/1550441275.jpg/preview', 'Indian', 1, 0, '2026-03-12 00:04:17', '2026-03-12 00:04:17'),
('99d123b8-5483-4306-8672-0fd7d1602f09', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pancake Bơ Sữa Phồng Xốp Bồng Bềnh', 'Tuyệt phẩm điểm tâm với những chiếc bánh nướng xốp nhẹ như mây, viền xém giòn tan tắm đẫm trong si-rô ngọt ngào lóng lánh.', '135000.00', 'https://www.themealdb.com/images/media/meals/rwuyqx1511383174.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('9a90443f-dba7-4229-ac5b-f30c5e9ac4ab', '346be777-07ed-426f-9be4-9bdec7356dcc', 'Mì Ý Linguine Sốt Tôm Cay Bỏng Trộn Đậu Hà Lan Giòn Sần Sật', 'Sợi mì luộc vớt ráo dẻo dai xóc tôm nõn áp chảo, dội thác xốt cay xé điểm xuyết hạt đậu Hà Lan ngọt lịm nhai sần sật vui miệng.', '250000.00', 'https://www.themealdb.com/images/media/meals/usywpp1511189717.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:00', '2026-03-12 00:04:00'),
('9a9c7f3f-25d5-47e7-9bea-b4d97c968a82', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Đậu Gà Đút Lò Fajitas Paprika Cháy Xém Giòn Rụm Lăn Lóc Rộp Vỏ', 'Hạt đậu bùi béo áo đẫm dầu ô-liu vẩy ớt xông khói nướng tạc vỡ rạn vỏ, rắc muối tiêu mặn mòi nhai giòn rôm rốp đầy thú vị.', '50000.00', 'https://www.themealdb.com/images/media/meals/tvtxpq1511464705.jpg/preview', 'Mexican', 1, 0, '2026-03-12 00:03:59', '2026-03-12 00:03:59'),
('9c47976a-9cfc-429b-9b3b-fa70451309fe', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Dumpling Khoai Tây Bryndzové Halušky', 'Những viên sủi cảo khoai tây dẻo quánh, xóc đẫm xốt phô mai cừu chua béo và lác đác vụn ba rọi chiên giòn tan mặn mòi.', '125000.00', 'https://www.themealdb.com/images/media/meals/g33c901763365484.jpg/preview', 'Slovakian', 1, 0, '2026-03-12 00:03:52', '2026-03-12 00:03:52'),
('9c5cd2c1-e370-4cfe-9286-89ed84d9adb2', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Thịt Băm Viên Kotlety Chiên Giòn Cắn Vỡ Vỏ Rụm', 'Phiên bản thịt viên đập dẹt áo bột xù chiên vàng ươm, phần nhân bò nấm hành tây tươm nước dùng đậm đà lan tỏa khắp khoang miệng.', '185000.00', 'https://www.themealdb.com/images/media/meals/vvn5f71764360273.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:04:33', '2026-03-12 00:04:33'),
('9dd6dc12-cb17-445f-8ed7-1ef6420608f2', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Pie Bò Sốt Mù Tạt Béo Ngậy', 'Tuyệt tác đút lò với lớp vỏ ngàn lớp giòn tan, bao bọc phần nhân bò hầm mềm nhừ hòa quyện xốt mù tạt nồng nàn kích vị.', '125000.00', 'https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg/preview', 'British', 1, 1, '2026-03-12 00:03:41', '2026-03-12 00:03:41'),
('9fd9ade5-116d-4df1-b0bf-827719591f10', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Trứng Omelette Khoai Tây Cuộn Xúc Xích Phô Mai Đút Lò Xém Mặt Cắn Ngập Răng Chảy Tràn Mượt', 'Khoai luộc bở tơi nhũn lụi xào lướt xúc xích tươm mỡ đổ trứng đun rát váng béo xém cạnh bục vỡ nứt rạn rỗng.', '200000.00', 'https://www.themealdb.com/images/media/meals/0y6uvc1763258983.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:04', '2026-03-12 00:04:04'),
('a08c2918-c89f-45aa-bef3-4dcdc2a408fc', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Mút Xốp Postre Chajá Lót Đào Kem Tươi Meringue', 'Món tráng miệng lộng lẫy kết cấu đan xen giữa mút xốp nhẹ bẫng, kem tươi mượt mà và mứt đào chua ngọt tan chảy êm ái vô cùng.', '105000.00', 'https://www.themealdb.com/images/media/meals/wii0591764375062.jpg/preview', 'Uruguayan', 1, 0, '2026-03-12 00:04:38', '2026-03-12 00:04:38'),
('a189abe2-f7bb-43ae-bdf8-9247d03b7234', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Cà Ri Thố Đất Handi Hành Phi Giòn Rụm', 'Cà ri gà vắt cốt dừa sánh đặc đun niêu đất bùng nổ hương sả quế tỏi, vùi ấp lớp hành phi vàng ruộm rải lác đác trên đỉnh.', '95000.00', 'https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg/preview', 'Indian', 1, 0, '2026-03-12 00:03:57', '2026-03-12 00:03:57'),
('a1d78ba2-261e-4552-8e27-10bb10384dd4', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Thố Gà Đút Lò Xốt Đỏ Enchilada Cháy Xém Phô Mai', 'Thịt gà hầm mềm trong xốt ớt đỏ rực Enchilada cay dịu đút lò, trùm lớp mền phô mai nướng váng vàng ươm dẻo quánh.', '50000.00', 'https://www.themealdb.com/images/media/meals/qtuwxu1468233098.jpg/preview', 'Mexican', 1, 0, '2026-03-12 00:03:57', '2026-03-12 00:03:57'),
('a274b1e4-6020-42a5-a130-71d584259a15', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Mì Ống Penne Xốt Cà Chua Ớt Tỏi Cay Nồng Rực Lửa Ý Nóng Bỏng Rát Lưỡi Đê Mê Trứ Danh Lấp Liếm Răng Khó Phai Nhức Nách', 'Mì lỏng lủng ấp chảo lỏng xốt đun lụt sùng ầm váng tỏi lựu lỏng lụt lắt tươm láng xào lạch.', '245000.00', 'https://www.themealdb.com/images/media/meals/ustsqw1468250014.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:21', '2026-03-12 00:04:21'),
('a54be857-2a6d-4997-9dce-3b69c21f899f', '70144013-483b-445f-b36f-01a2ed3c9eb8', 'Súp Đậu Chẻ Hầm Chân Giò Khói Sánh Đặc Vắt Nước Xương Ngọt Lịm Khó Cưỡng Đậm Đặc Bỏng Rát Cay Xé Lưỡi Đê Mê Tê Ngây Cực Đỉnh', 'Đậu đun lụt nước bốc sùng ầm váng lỏng lủng hầm rục lỏng xé tã lỏng lấp lựu văng láng.', '55000.00', 'https://www.themealdb.com/images/media/meals/xxtsvx1511814083.jpg/preview', 'Canadian', 1, 0, '2026-03-12 00:04:22', '2026-03-12 00:04:22'),
