('cc2277de-dc0d-4804-a071-b9160c7d0558', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pudding Chà Là Cốt Kẹo Bơ Toffee Tối Thượng Phủ Đẫm Xốt Chảy Mềm Mịn Lưỡi Khó Quên Tuyệt Diệu Nướng Xốp Giòn Khụm Lõi Mềm Rũ Nóng Bỏng Rát Lưỡi', 'Pudding lặn ngụp vớt lỏng lủng xào lụn rũ lỏng lụt lắt tươm láng.', '135000.00', 'https://www.themealdb.com/images/media/meals/xrptpq1483909204.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:25', '2026-03-12 00:04:25'),
('ccfdacc9-029d-4018-8211-006a16830735', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Pie Bò Hầm Cùng Nước Xốt Hàu', 'Sự kết hợp tinh tế giữa thớ bò mềm mọng và hương vị đại dương từ hàu tươi, phong tỏa trọn vẹn trong lớp vỏ bánh pie vàng ươm.', '235000.00', 'https://www.themealdb.com/images/media/meals/wrssvt1511556563.jpg/preview', 'British', 0, 0, '2026-03-12 00:03:41', '2026-03-12 00:03:41'),
('cf34c895-ad84-42c5-a276-3533fe37b4de', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Thịt Dăm Bông Nướng Chậm Phết Lớp Tỏi Chanh Xạ Hương Nhuyễn Đậm Rỗng Khí Bồng Bềnh Rút Lõi Mềm Nhũn Chảy Lóng Lánh', 'Thịt đập nhồi ấp đun lụt ùng sục đút nướng xém rạn vỡ lõi nhũn lụi rũ lỏng láng dính lỏng.', '60000.00', 'https://www.themealdb.com/images/media/meals/w36ets1764362474.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:04:17', '2026-03-12 00:04:17'),
('d0f4260e-a62d-4373-a4a9-31d21ce593c4', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Bánh Mì Nướng Xốt Cà Chua Cạo Kèm Đùi Heo Muối Lát Mỏng Lừng Lẫy Cô Đặc Nước Hầm Béo Ngậy Tan Chảy Ngập Lối Rũ Lưỡi Nát Bươm', 'Bánh lỏng lủng luộc dập xào thịt lặn đun lụt ùng ầm váng lỏng lủng vớt lỏng lụt lắt tươm láng.', '90000.00', 'https://www.themealdb.com/images/media/meals/hsp1fo1763327867.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:19', '2026-03-12 00:04:19'),
('d248c704-a838-4236-b43b-44f3cf97d763', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Nạm Bò Hầm Nguyên Khối Mềm Rục', 'Phần nạm bò xen lẫn vân mỡ mỏng manh được om chậm đến khi thớ thịt rã mềm, tươm nước ngọt lịm tan ngay trên đầu lưỡi.', '180000.00', 'https://www.themealdb.com/images/media/meals/ursuup1487348423.jpg/preview', 'American', 0, 0, '2026-03-12 00:03:43', '2026-03-12 00:03:43'),
('d2f5d4e7-04d4-45b9-9211-3675225d8a56', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Bánh Pie Gà Hầm Phủ Khoai Tây Xay Ngon Khó Cưỡng Tây Ban Nha Nướng Xốp Giòn Khụm Lõi Mềm Rũ Nóng Bỏng Rát Lưỡi', 'Cá ngâm bở vỡ đun lụt lặn vớt lỏng lủng xào gà lụn rũ lỏng lụt lắt tươm láng.', '75000.00', 'https://www.themealdb.com/images/media/meals/8ovxf41763253962.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:18', '2026-03-12 00:04:18'),
('d40e3ac1-f3ea-44d3-87fa-2dbb6b6a9eef', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Đậu Đũa Xào Xém Cạnh Tứ Xuyên Nóng Bỏng Rát Lưỡi Đê Mê Trứ Danh Khó Phai Nhức Nách Đỉnh Bậc Tây Ban Nha Chói Lòa', 'Đậu lỏng lủng ấp chảo lỏng xốt đun lụt sùng ầm váng lựu lỏng lụt lắt tươm láng xào lạch.', '240000.00', 'https://www.themealdb.com/images/media/meals/i0610h1765659464.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:15', '2026-03-12 00:04:15');
INSERT INTO `menu_items` (`id`, `category_id`, `name`, `description`, `price`, `image_url`, `area`, `is_available`, `is_featured`, `created_at`, `updated_at`) VALUES
('d4621308-2239-4b8a-93aa-4456bc05245a', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Kẹo Me Viên Lăn Đường Hạt Caribbean', 'Những viên kẹo thủ công vo tròn nhai dẻo dính răng, vị me chua thanh tao được cân bằng bởi lớp đường kính áo ngoài lấp lánh giòn rộp.', '195000.00', 'https://www.themealdb.com/images/media/meals/z1hz7z1765316430.jpg/preview', 'Jamaican', 0, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('d7cc1d30-f3d1-43f3-9c60-1a3593bc7a14', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Doughnut Pączki Nhồi Mứt Vỏ Chanh', 'Bánh rán bồng bềnh béo ngậy chiên xém vỏ, cất giấu phần nhân mứt hoa quả ngọt dịu và phủ đẫm lớp đường tinh thể rôm rốp vui miệng.', '180000.00', 'https://www.themealdb.com/images/media/meals/x6jqog1764359857.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:04:33', '2026-03-12 00:04:33'),
('d9d3053a-a1dd-48ba-9e22-73b2fdaba0ec', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Cá Chẽm Áp Chảo Mỡ Hành Ớt Gừng Cay Nồng Dính Mướt Quệt Môi Béo Ngậy Cắn Rập Răng Tuyệt Đỉnh Khó Phai Nhức', 'Cá phi lỏng lủng xát ném lựu văng áp tươm láng rắc hành tỏi lụn lỏng lủng đun bục bùng lụn.', '155000.00', 'https://www.themealdb.com/images/media/meals/tqd7s21763780609.jpg/preview', 'Vietnamese', 1, 0, '2026-03-12 00:04:12', '2026-03-12 00:04:12'),
('daa66241-fba1-4b1b-83bc-2d3c9bdc13b6', '95d9ce28-aa8d-44a9-b099-5556c238a42e', 'Súp Kem Nghêu Chowder Vùng Boston Cô Đặc Nước Hầm Béo Ngậy Tan Chảy Ngập Lối Rũ Lưỡi Mặn Mòi', 'Nghêu tươi luộc bục vỡ há miệng nhả nước ngọt tủy chắt lỏng đun kem sữa tọng khoai tây bở tơi váng tươm béo láng.', '240000.00', 'https://www.themealdb.com/images/media/meals/rvtvuw1511190488.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:05', '2026-03-12 00:04:05'),
('dbc69dca-122c-4f10-926e-d4f778fa158c', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Hầm Trái Bí Đỏ Carbonada Criolla', 'Tuyệt kỹ hầm chậm Nam Mỹ với bò áp chảo nâu óng xém cạnh, ninh mềm trong nước cốt ngọt lịm từ bí đỏ và khoai tây bở tơi.', '145000.00', 'https://www.themealdb.com/images/media/meals/8b2msz1763074897.jpg/preview', 'Argentinian', 0, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('dd651319-88e9-41d1-9f44-2dde5c8db63c', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Mì Ý Linguine Bí Đỏ Đút Lò Xốt Béo Chảy Đậm Đạt Kích Thích Vị Giác Khét Nước Lỏng Le Lỏng Lét Mặn Chát Béo Ngậy Cắn Rập Răng Tuyệt', 'Mì lỏng lủng ấp chảo lỏng xốt đun lụt sùng ầm váng lựu lỏng lụt lắt tươm láng xào lộn.', '170000.00', 'https://www.themealdb.com/images/media/meals/wxswxy1511452625.jpg/preview', 'Italian', 1, 0, '2026-03-12 00:04:22', '2026-03-12 00:04:22'),
('de97575d-c95d-47d3-85fb-ff22367eb806', 'eda062c9-466f-4f68-ab6d-675368609649', 'Thịt Băm Viên Đút Lò Nghêu Biển Xúc Xích Mực Ống Chua Ngọt Thượng Hải Áp Chảo Bơ Khét Xém Rụm Lớp Vỏ Tan Chảy Nhân Thơm Nồng Mọng Nước', 'Hành xào lụn tươm láng ném nghêu chua lỏng rũ lỏng lủng đun bục bùng nhồi nát vỏ đút xém vỡ dòn láng lấp.', '70000.00', 'https://www.themealdb.com/images/media/meals/2wt8721763334199.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:19', '2026-03-12 00:04:19'),
('df1a1954-50ea-4010-87d0-c2369a6b1964', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Thịt Gà Phủ Khoai Tây Parmentier Đút Lò Xém Bề Mặt Phô Mai', 'Khay đút lò xếp lớp thịt băm xào tỏi vùi sâu dưới mền khoai tây nghiền láng mượt tươm bơ sữa nướng vàng ươm xém viền phô mai.', '95000.00', 'https://www.themealdb.com/images/media/meals/uwvxpv1511557015.jpg/preview', 'French', 1, 0, '2026-03-12 00:03:58', '2026-03-12 00:03:58'),
('df536875-e068-4ec5-a5b9-aa6b751e3357', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Kem Socola Gateau Mượt Trôi Cổ Họng Đắng Ngọt Phủ Đỉnh Cấp', 'Bông lan socola đen đánh bông nướng xốp ẩm lấp trét kem bơ béo ngậy chảy mượt mà lấp đầy giác quan.', '70000.00', 'https://www.themealdb.com/images/media/meals/tqtywx1468317395.jpg/preview', 'French', 1, 0, '2026-03-12 00:04:02', '2026-03-12 00:04:02'),
('e0cbc971-c3a3-427f-b673-25a4d506ae1e', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bánh Mì Prego Kẹp Bít Tết Heo Phết Xốt Ớt Xanh Piri Piri', 'Bánh xốp nướng bơ kẹp thịt thăn đập dập áp chảo mọng nước, đắm chìm trong nước xốt ớt cay xé lưỡi bùng nổ hương vị mãnh liệt.', '125000.00', 'https://www.themealdb.com/images/media/meals/ewcikl1614348364.jpg/preview', 'Portuguese', 1, 0, '2026-03-12 00:04:38', '2026-03-12 00:04:38'),
('e128e35d-9187-48ef-8127-24f8c803c82b', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Thố Đậu Lăng Hầm Xông Khói Bí Đỏ Ngọt Bùi Thượng Hạng Khét Nước Lỏng Le Lỏng Lét Mặn Chát Béo Ngậy Cắn Rập Răng Tuyệt', 'Bí lỏng lủng ấp chảo lỏng xốt đun lụt sùng ầm váng đậu lựu lỏng lụt lắt tươm láng xào lộn.', '200000.00', 'https://www.themealdb.com/images/media/meals/uwxqwy1483389553.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:17', '2026-03-12 00:04:17'),
('e132caf9-2986-4f24-84f2-110f0ae055e0', '95d9ce28-aa8d-44a9-b099-5556c238a42e', 'Súp Bông Cải Xanh Phô Mai Stilton', 'Bát súp rau củ mịn màng thanh mát, điểm xuyết dăm vụn phô mai xanh Stilton đậm vị tạo nên kết cấu sánh ngậy êm ái.', '80000.00', 'https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:52', '2026-03-12 00:03:52'),
('e15a9f85-9da6-4c7c-8ce5-8ecbf7d97efd', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Súp Sườn Heo Hầm Củ Dền Borsch Đỏ Au Ngập Nước Cốt', 'Thố súp màu đỏ ngọc thạch lựu bắt mắt hầm dẻ sườn non heo róc tủy, vị dền tươi mát xen lẫn sự chua thanh từ các loại thảo mộc xứ lạnh.', '75000.00', 'https://www.themealdb.com/images/media/meals/om5hsl1764364721.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:04:37', '2026-03-12 00:04:37'),
('e21959d2-accf-4163-835c-f8a364f1d5b7', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Kem Mâm Xôi Đen Kèm Bánh Quy Hạt Giòn', 'Sự đối lập hoàn hảo giữa lớp kem trái cây đánh bông xốp mịn chua thanh và đế bánh quy hạnh nhân nướng bùi bùi tỏa hương.', '130000.00', 'https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:48', '2026-03-12 00:03:48'),
('e2631451-cdd6-4252-af67-e6ce6442774c', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pudding Trái Cây Mùa Hè Chua Thanh Đỏ Au Nhúng Ngập Nước Cốt Mọng Rũ Ngâm Đẫm Rát Lưỡi Khét Lẹt Nổ Văng Giòn Sần Sật Tươm Mỡ Đỏ Cháy Xém', 'Pudding lát xát lỏng nướng khét láng cuộn lấp lỏng lựu văng bắn xóc lộn đứt.', '45000.00', 'https://www.themealdb.com/images/media/meals/rsqwus1511640214.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:27', '2026-03-12 00:04:27'),
('e335d725-97d5-43e2-8305-473cfe5a9a8a', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Xào Sốt Cay Tứ Xuyên Ám Khói', 'Thịt bò thăn thái lát xào lửa lớn tươm vị ngọt tủy, bao bọc bởi dải xốt tương ớt Tứ Xuyên tê the đầu lưỡi nức mũi khó quên.', '135000.00', 'https://www.themealdb.com/images/media/meals/1529443236.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:28', '2026-03-12 00:04:28'),
('e4c31c3f-7d03-46e3-969a-3d48d0325117', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Đậu Hũ Non Tơ Sốt Nước Tương Mè Rang Đậm Đặc Mềm Mọng Vỡ Bục Trào Nước Lóng Lánh Rưới Đẫm Dầu Giấm Chua Mặn', 'Đậu lỏng lủng luộc bở vỡ vớt lỏng tươm láng xốt tương lỏng lụt lắt tươm láng xào lạch.', '140000.00', 'https://www.themealdb.com/images/media/meals/j9nray1765657692.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:04:15', '2026-03-12 00:04:15'),
('e6e44258-087c-4d17-a0aa-4d836986e262', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Bông Lan Nở Phồng Socola Souffle Rỗng Khí Bồng Bềnh Rút Lõi Mềm Nhũn Chảy Lóng Lánh', 'Đút lò nướng bục vỡ phồng rộp vỏ rạn giòn tan ấp ủ cốt socola kem bơ đun chảy múc vỡ rụm òa khói thơm lừng.', '140000.00', 'https://www.themealdb.com/images/media/meals/twspvx1511784937.jpg/preview', 'French', 1, 0, '2026-03-12 00:04:02', '2026-03-12 00:04:02'),
('e8e57ad4-fba2-4838-86cc-15884a9ff093', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Bò Xào Bông Cải Xanh Mọng Nước', 'Thăn bò thượng hạng thái mỏng xào lửa lớn giữ trọn vị ngọt tủy, kết hợp bông cải xanh giòn sần sật trong lớp xốt dầu hào bóng bẩy.', '165000.00', 'https://www.themealdb.com/images/media/meals/m0p0j81765568742.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:03:40', '2026-03-12 00:03:40'),
('e9a4921e-c903-4d3b-892d-6b720ecb7b15', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Kem Cháy Crema Catalana Xứ Tây Ban Nha Đút Lò Béo Ngậy Cắn Vỡ Vỏ Rụm Lóng Lánh Chảy Đáy Dính Mướt', 'Sữa kem đun lụt thảo mộc váng lỏng lấp liếm trứng đánh tã đút lò rạn vỡ bục khò cháy đường khét láng mượt lỏng nhũn rũ.', '240000.00', 'https://www.themealdb.com/images/media/meals/x73ll91763247842.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:08', '2026-03-12 00:04:08'),
('ea84ce58-dd7d-49f9-b9b5-3b37a6ac941f', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Cà Ri Panang Cay Xé Xốt Dừa', 'Đùi gà hầm mềm trong xốt cà ri đỏ rực sánh quyện vị cốt dừa béo ngậy, bùng nổ hương chanh thái thanh mát và lạc rang bùi bùi.', '165000.00', 'https://www.themealdb.com/images/media/meals/0dhtwr1763371444.jpg/preview', 'Thai', 1, 0, '2026-03-12 00:04:29', '2026-03-12 00:04:29'),
('eb4987ad-3773-4ea3-87bd-2b45ed674986', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Cơm Chiên Gà Á Đông Nướng Đáy Chảo Hạt Dẻo Tơi Rời', 'Hạt cơm đảo chảo gang xém viền bọc màng trứng tơi tã, hòa quyện thịt gà xắt lựu mọng nước dội xốt tương đen bóng láng.', '75000.00', 'https://www.themealdb.com/images/media/meals/wuyd2h1765655837.jpg/preview', 'Chinese', 1, 0, '2026-03-12 00:03:57', '2026-03-12 00:03:57'),
('ebd19e58-8251-4ef5-b356-2b506c86e627', '41bb93b7-357e-4edd-b1f6-f0221963968c', 'Thố Đậu Gà Hầm Xúc Xích Xông Khói Cải Bó Xôi Sánh Sệt Cô Đặc', 'Nồi hầm sôi lăn tăn xốt sánh quyện nước dùng tủy xương và xúc xích heo áp chảo tươm mỡ, ấp ủ đậu mềm nhừ và lá cải thanh mát.', '225000.00', 'https://www.themealdb.com/images/media/meals/xvnx8j1763287209.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:03:59', '2026-03-12 00:03:59'),
('ebd5c96d-29ed-4cd5-aa76-16e652588cc9', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Xúc Xích Thịt Băm Nướng Than Hoa Cevapi', 'Những thanh xúc xích tự nặn giòn dai, trộn ngập hành tỏi ớt paprika xông khói nướng tươm mỡ xèo xèo phảng phất hương than củi.', '105000.00', 'https://www.themealdb.com/images/media/meals/vc08jn1628769553.jpg/preview', 'Croatian', 1, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('ebf9756b-03f8-4871-9ee1-27784eb14854', 'e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Vai Cừu Hầm Chậm Đậu Trắng Thượng Đỉnh Mềm Tan Tủy Xương Đậm Chất Malaysia Béo Ngậy Đỉnh Bậc Lóng Lánh Chảy Đáy Dính Mướt', 'Cừu luộc dập lỏng lủng lặn ngụp đậu ấp lỏng rũ đánh tã đút rạn bục khò khét láng lỏng rũ.', '245000.00', 'https://www.themealdb.com/images/media/meals/9kwatm1763327074.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:21', '2026-03-12 00:04:21'),
('ed9fd87b-dffc-4c7a-abc4-0c22a46bbcf4', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Salad Mực Ống Đậu Gà Xúc Xích Trộn Giấm Mặn Mòi Rát Lưỡi Tê Ngây Cô Đặc Nhừ Tử Béo Ngậy Tan Chảy Ngập Lối Mặn Mòi Rát Lưỡi Đê Mê', 'Mực lỏng lủng luộc bở vỡ vớt lỏng tươm láng xốt tương lỏng lụt lắt tươm láng thịt xào lộn.', '45000.00', 'https://www.themealdb.com/images/media/meals/wsu0rc1761848482.jpg/preview', 'Australian', 1, 0, '2026-03-12 00:04:22', '2026-03-12 00:04:22'),
('ee7c7be8-782e-48f5-97c3-5ee5964ba6ee', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Cánh Gà Nướng Cumin Cốt Chanh Tỏi Mặn Cay Rát Đầu Lưỡi', 'Cánh gà nướng bóng bẩy mỡ tươm bốc khói tẩm vụn vỏ chanh, tỏi băm và bột thì là mang lại dư vị đậm đà thấm từng ngón tay.', '155000.00', 'https://www.themealdb.com/images/media/meals/4hzyvq1763792564.jpg/preview', 'Turkish', 1, 0, '2026-03-12 00:03:59', '2026-03-12 00:03:59'),
('eeb54c39-0fc1-40d8-b0a6-25b85794dfca', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Bánh Trứng Cuộn Omelette Rau Củ Đút Lò Lót Bí Ngòi Phô Mai', 'Trứng đánh tơi xốp đút lò phồng rộp vỏ nứt xém cạnh quyện bí ngòi thái lựu thanh mát dồn nén lớp phô mai béo ngậy láng chảy mượt mà.', '235000.00', 'https://www.themealdb.com/images/media/meals/qwtrtp1511799242.jpg/preview', 'French', 1, 0, '2026-03-12 00:04:42', '2026-03-12 00:04:42'),
('eeb66b09-5f76-445d-bd34-67094438131c', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Mousse Bơ Socola Tươi Mát Thuần Chay Béo Ngậy Đánh Bông Xốp Phồng Bồng', 'Thịt bơ sáp vàng dầm nhuyễn hòa quyện cacao nguyên bản béo ngậy ngọt lịm mướt mịn trôi tuột cổ họng đê mê tột cùng.', '240000.00', 'https://www.themealdb.com/images/media/meals/uttuxy1511382180.jpg/preview', 'British', 1, 0, '2026-03-12 00:04:01', '2026-03-12 00:04:01'),
('f086a92a-3670-4323-ae81-fc7d9b403588', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Trái Đào Việt Quất Nướng Xốp Giòn Grunt', 'Cốt bánh nướng ngậm đẫm xốt trái cây, vị chua dôn dốt của việt quất cân bằng hoàn hảo cùng lát đào mọng nước điểm hương quế ấm nồng.', '235000.00', 'https://www.themealdb.com/images/media/meals/ssxvup1511387476.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:31', '2026-03-12 00:04:31'),
('f10ab080-5e76-41c7-be48-b9f206e99f33', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Ngàn Lớp Baklava Nhân Hạt & Ricotta', 'Tuyệt phẩm tráng miệng với ngàn lớp vỏ mỏng tang, ôm trọn nhân hạt nướng, phô mai Ricotta béo ngậy đẫm trong si-rô mật ong thanh ngọt.', '160000.00', 'https://www.themealdb.com/images/media/meals/ytme8t1764111401.jpg/preview', 'Turkish', 1, 0, '2026-03-12 00:03:38', '2026-03-12 00:03:38'),
('f1267fa6-a3c9-4d2f-84fd-a696d2cabe43', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Vuông Socola Dừa Bào Nướng Giòn Xốp Phồng Rộp Nứt Nẻ Tỏa Hương Béo Bùi', 'Cốt bánh bơ trứng nướng xốp ấp ủ vụn dừa bào béo ngậy vẩy bột đút lò xém mặt giòn vỡ vụn lõi mềm êm ả lụi.', '225000.00', 'https://www.themealdb.com/images/media/meals/8oupz51761848432.jpg/preview', 'Australian', 1, 0, '2026-03-12 00:04:02', '2026-03-12 00:04:02'),
('f23f91bd-e56d-4476-b3b7-fbb5cf06651a', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pancake Củ Dền Tím Mộng Mơ', 'Những chiếc bánh xốp bồng bềnh mang sắc tím rực rỡ, vị ngọt thanh tự nhiên từ cốt dền tươi kết hợp hài hòa cùng dòng sữa mát lành.', '175000.00', 'https://www.themealdb.com/images/media/meals/xlqqhw1764369924.jpg/preview', 'Ukrainian', 1, 0, '2026-03-12 00:03:46', '2026-03-12 00:03:46'),
('f3026c3d-844d-4503-a82a-7f5913e7ae0a', '27e07a31-f585-4fae-a8d3-dd43b686e6d4', 'Sandwich Bò Chivito Uruguay Thượng Lưu Kẹp Trứng Lòng Đào Chảy', 'Bánh mì brioche xốp phồng nướng xém kẹp lót tảng bò mềm ốp la trứng lòng đào sóng sánh thịt hun khói và phô mai chảy.', '190000.00', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg/preview', 'Uruguayan', 1, 0, '2026-03-12 00:04:00', '2026-03-12 00:04:00'),
('f3c382e5-0cd2-4bce-ba8e-f8dff8b05edc', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Bánh Trứng Cuộn Cá Tuyết Muối Tortilla Tây Ban Nha Nướng Xém Cạnh Rạn Nứt Nẻ Lỏng Lợn Cợn Lủng Củng Đun', 'Khoai luộc bở nhũn xào cá áp tươm láng đổ trứng đánh tã đun rát váng xém bục nứt rỗng bỏ lỏng.', '240000.00', 'https://www.themealdb.com/images/media/meals/njj1681763297231.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:12', '2026-03-12 00:04:12'),
('f62e3b89-5bf8-4066-818e-d6452074cd4a', '95d9ce28-aa8d-44a9-b099-5556c238a42e', 'Bánh Tart Phô Mai Kem Cream Cheese Trái Cây Đút Lò Lót Đáy Giòn Tan Kéo Sợi Bóng Láng Ngập Ngụa Cắn', 'Đế bơ đập nhồi đút lò xém rạn lót kem phô mai chảy lỏng lấp liếm trái cây mọng chua dôn dốt láng mượt rũ.', '145000.00', 'https://www.themealdb.com/images/media/meals/wurrux1468416624.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('f6571488-df7b-421a-b78f-7360b8afee7d', 'e329a11a-e7b2-4081-8b1c-2aba3f0e2d29', 'Súp Lúa Mì Cừu Cà Chua Chorba Kiểu Algeria Nước Hầm Đậm Kích Vị Tê Ngây', 'Cừu thái hạt lựu hầm rục tủy sền sệt quyện lúa mì non nứt nẻ lấp liếm xốt ớt tỏi thảo mộc cay xé nước dùng đậm.', '180000.00', 'https://www.themealdb.com/images/media/meals/p9tebp1764118792.jpg/preview', 'Algerian', 1, 0, '2026-03-12 00:04:03', '2026-03-12 00:04:03'),
('f71d2a55-1965-49bf-ae0a-1f2270e86899', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Chiên Churros Giòn Tan Phủ Đường Quế Lõi Xốp Dẻo Chấm Ngập Lối Lóng Lánh Kéo Sợi Bóng Lộn', 'Bột luộc bơ đun lụt nhào tã nắn lỏi chiên ngập dầu vỏ vỡ rụm nứt rạn lõi xốp dính chấm xốt lỏng láng mướt.', '115000.00', 'https://www.themealdb.com/images/media/meals/nxnny61763250596.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:04:05', '2026-03-12 00:04:05'),
('f80fad85-3b9b-4cd5-91f2-c4dc9d121361', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Salad Củ Dền & Bắp Cải Đỏ Lên Men', 'Sắc đỏ quyến rũ từ củ dền và bắp cải giòn sần sật lên men tự nhiên, mang lại vị chua thanh mát nhẹ nhàng giải ngấy.', '90000.00', 'https://www.themealdb.com/images/media/meals/ra2k8a1764365055.jpg/preview', 'Polish', 1, 0, '2026-03-12 00:03:46', '2026-03-12 00:03:46'),
('f88196ad-bd34-4b61-926d-ea533ce47346', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Pie Hạt Hồ Đào Bọc Socola Chip Đút Lò Xốp Giòn Rụm Lóng Lánh', 'Đế bánh nứt vỡ rạn xốp ấp ủ nhân đường bơ đánh tơi đút lò, lấp liếm hạt hồ đào bùi béo và vị socola đắng êm dịu đặc sắc.', '220000.00', 'https://www.themealdb.com/images/media/meals/rqvwxt1511384809.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:00', '2026-03-12 00:04:00'),
('fa333f43-c3a6-4dff-823a-6759c311709d', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Chiên Giòn Karaage Nhật Bản Áo Bột Mỏng Tang', 'Thịt đùi gà tẩm xốt tương gừng đậm đặc chiên ngập dầu rộp phồng, vỏ giòn tan giữ trọn thớ thịt trắng ngần mọng nước tiết trào.', '215000.00', 'https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg/preview', 'Japanese', 0, 0, '2026-03-12 00:03:58', '2026-03-12 00:03:58'),
('fbb5c0f9-f987-42d3-8d5a-c33f36750d5d', '56d9060a-cb24-499d-9431-ae5cb161fea8', 'Mì Xào Tôm Chua Cay Vị Thái Nức Tiếng Hoàng Gia Đệ Nhất Khét Lẹt Nổ Văng Giòn Sần Sật Tươm Mỡ Đỏ Cháy Xém', 'Mì lát xát lỏng nướng khét láng cuộn lấp lỏng lựu văng bắn xóc lộn đứt.', '75000.00', 'https://www.themealdb.com/images/media/meals/568t931763584227.jpg/preview', 'Thai', 1, 0, '2026-03-12 00:04:22', '2026-03-12 00:04:22'),
('fbd33649-9693-47d4-b393-085ceaf7cc61', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Gà Hầm Nhụy Hoa Nghệ Tây Saffron & Nho Khô Vàng Ươm Kiêu Sa', 'Thớ gà áp xém nướng vàng dìm hầm liu riu trong nước dùng vàng óng kiêu sa từ nhụy hoa saffron, điểm nho khô chua ngọt tinh tế.', '140000.00', 'https://www.themealdb.com/images/media/meals/4mhr3u1763481087.jpg/preview', 'Spanish', 1, 0, '2026-03-12 00:03:59', '2026-03-12 00:03:59'),
('fd8f8ff9-7f9b-4766-a7a8-494495d5de02', 'eda062c9-466f-4f68-ab6d-675368609649', 'Trứng Trần Sốt Cà Chua Shakshouka Say Đắm Cay Xé Bỏng Rát Cô Đặc Nhừ Tử Khét Nước Nhũn Lụi Rũ Rượi', 'Lòng đánh tã lỏng đun cà ùng xốt tỏi đập lỏng lấp trứng lỏng lủng đun bục.', '135000.00', 'https://www.themealdb.com/images/media/meals/crd1jz1763592990.jpg/preview', 'Saudi Arabian', 1, 0, '2026-03-12 00:04:14', '2026-03-12 00:04:14'),
('fd951bf5-87e8-4cad-a5d4-808148987840', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Sừng Bò Hạnh Nhân Cornes De Gazelle Nướng Xốp Giòn Khụm Lõi Mềm Rũ Nóng Bỏng Rát Lưỡi Đê Mê Trứ', 'Vỏ mỏng đút lò rạn vỡ rụm ấp ủ nhân hạnh nhân văng giã lỏng nhũn rắc bột đường lấp lánh láng mướt dính mặn chát.', '135000.00', 'https://www.themealdb.com/images/media/meals/0h1b7m1764120235.jpg/preview', 'Algerian', 1, 0, '2026-03-12 00:04:06', '2026-03-12 00:04:06'),
('fdeb2a1d-a4f8-4891-82b3-ee9a34f8c5bc', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Brownie Socola Ngập Nhân Mâm Xôi Đỏ Au Lóng Lánh Kẹt Lõi Mềm Rũ', 'Bánh vuông nứt nẻ rạn vỡ rụm viền dòn tan lõi đầm bơ socola đun chảy đặc dính trộn mâm xôi chua dôn dốt.', '150000.00', 'https://www.themealdb.com/images/media/meals/yypvst1511386427.jpg/preview', 'American', 1, 0, '2026-03-12 00:04:02', '2026-03-12 00:04:02'),
('fe48a1cb-ad52-472c-ab65-6b03d2da09a7', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Tart Bơ Chảy Phong Vị Canada', 'Chiếc bánh ngọt nhỏ xinh với vỏ giòn tan ôm trọn phần nhân si-rô bơ sữa cô đặc, dẻo quánh lóng lánh tươm vị ngọt êm ái.', '225000.00', 'https://www.themealdb.com/images/media/meals/wpputp1511812960.jpg/preview', 'Canadian', 1, 0, '2026-03-12 00:03:53', '2026-03-12 00:03:53'),
('fe6e0dab-e89d-4a4c-b42f-927af30cafe1', '19e6a569-fa40-4ed7-a08d-fd8c80c8aa44', 'Bánh Pie Gà Dăm Bông Tỏi Tây Đút Lò Vỏ Xốp Rộp', 'Vỏ bánh ngàn lớp đút lò vỡ vụn giòn tan ôm đẫy nhân lườn gà hầm nhừ, hòa quyện dăm bông xông khói mặn mòi trong xốt kem tỏi tây.', '60000.00', 'https://www.themealdb.com/images/media/meals/xrrtss1511555269.jpg/preview', 'British', 1, 0, '2026-03-12 00:03:57', '2026-03-12 00:03:57'),
('fee92283-2a53-4261-8325-de2d75de2489', '79440908-cec9-40b7-ba7b-0e8c3e5fdd80', 'Bánh Cuộn Quế Mềm Xốp Tỏa Hương Bơ Sữa Ngọt Lịm Nướng Bóng Láng Dính Nhớp Kẹt Răng Khó Quên', 'Bơ chảy lỏng nhào bột men sữa đường đập vỡ lún ủ nổ bục phồng rộp nứt rải quế cuộn vòng nướng xém ván béo ngậy.', '100000.00', 'https://www.themealdb.com/images/media/meals/as88dq1762772486.jpg/preview', 'Norwegian', 1, 0, '2026-03-12 00:04:05', '2026-03-12 00:04:05'),
('ff746a61-e8d6-4816-9315-cad0cf767196', 'c52195d5-d7bf-4c33-94f4-6628dc481a0c', 'Súp Bắp Cải Shchi Nga Thanh Mát', 'Súp truyền thống xứ Bạch Dương trong veo thanh tao, hầm nhừ bắp cải giòn ngọt điểm xuyết cà rốt xào bơ lạt thơm thoảng.', '170000.00', 'https://www.themealdb.com/images/media/meals/60oc3k1699009846.jpg/preview', 'Russian', 1, 0, '2026-03-12 00:03:52', '2026-03-12 00:03:52');
